data.query:
mutation CreateComment($input: CommentCreateInput!) {
    commentCreate(input: $input) {
        success
        comment {
            id
            body
            url
            createdAt
            updatedAt
            user {
                id
                name
            }
            issue {
                id
                identifier
            }
            parent {
                id
            }
        }
    }
}
